export const GENERATED_QUESTIONS_4: SeedQuestion[] = [
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Demonstrate Knowledge of the General Orientation of Human Anatomy","difficulty":2,"stem":"When a person becomes overheated, sweat glands activate and blood vessels in the skin dilate to release heat, returning body temperature toward its set point. This response is the best example of which physiological principle?","options":["Negative feedback maintaining homeostasis","Active transport across a membrane","Metabolic conversion of nutrients to energy","Positive feedback amplifying a change"],"correct":[0],"explanation":"Negative feedback opposes a deviation from the set point. Rising body temperature triggers cooling mechanisms (sweating, vasodilation) that bring the temperature back down, the hallmark of homeostatic negative feedback. Positive feedback would amplify the change rather than reverse it."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Demonstrate Knowledge of the General Orientation of Human Anatomy","difficulty":1,"stem":"Which sequence correctly lists the levels of structural organization in the human body from simplest to most complex?","options":["Cells, tissues, organs, organ systems","Tissues, cells, organs, organ systems","Cells, organs, tissues, organ systems","Organs, tissues, cells, organ systems"],"correct":[0],"explanation":"Cells combine to form tissues, tissues form organs, and organs working together form organ systems. This is the standard hierarchy of structural organization moving from simplest to most complex."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Demonstrate Knowledge of the General Orientation of Human Anatomy","difficulty":2,"stem":"The heart and lungs are protected by the rib cage and are located in which body cavity?","options":["Abdominal cavity","Thoracic cavity","Pelvic cavity","Cranial cavity"],"correct":[1],"explanation":"The thoracic (chest) cavity houses the heart and lungs and is enclosed by the rib cage. The abdominal cavity contains digestive organs, the pelvic cavity holds the bladder and reproductive organs, and the cranial cavity holds the brain."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Demonstrate Knowledge of the General Orientation of Human Anatomy","difficulty":2,"stem":"Using the standard nine-region scheme of the abdomen, which region lies directly superior to the umbilical region?","options":["Hypogastric region","Left iliac region","Epigastric region","Right lumbar region"],"correct":[2],"explanation":"The epigastric region is the central region directly above (superior to) the umbilical region. The hypogastric region is below the umbilical region, while the lumbar and iliac regions are lateral."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Neuromuscular System","difficulty":2,"stem":"Which sequence correctly traces the pathway of a simple reflex arc?","options":["Effector, motor neuron, interneuron, sensory neuron, receptor","Receptor, sensory neuron, interneuron, motor neuron, effector","Sensory neuron, receptor, interneuron, effector, motor neuron","Receptor, motor neuron, interneuron, sensory neuron, effector"],"correct":[1],"explanation":"A reflex arc begins at a receptor that detects a stimulus, sends the signal along a sensory (afferent) neuron to an interneuron in the spinal cord, which routes it to a motor (efferent) neuron that activates an effector such as a muscle."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Neuromuscular System","difficulty":2,"stem":"In a myelinated axon, the action potential appears to jump from one node of Ranvier to the next. What is the main benefit of this saltatory conduction?","options":["It eliminates the need for neurotransmitters","It prevents the neuron from ever depolarizing","It increases the speed at which the impulse travels","It allows the impulse to travel in both directions at once"],"correct":[2],"explanation":"Myelin insulates the axon so the action potential regenerates only at the gaps (nodes of Ranvier), jumping from node to node. This saltatory conduction greatly increases conduction speed compared with unmyelinated axons."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Neuromuscular System","difficulty":1,"stem":"The gaps in the myelin sheath where the axon membrane is exposed are called the","options":["Motor end plates","Nodes of Ranvier","Dendritic spines","Synaptic clefts"],"correct":[1],"explanation":"The nodes of Ranvier are the periodic gaps between myelin segments where voltage-gated channels regenerate the action potential, enabling saltatory conduction. A synaptic cleft is the space between neurons, and the motor end plate is part of the neuromuscular junction."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Neuromuscular System","difficulty":2,"stem":"In a withdrawal reflex, such as pulling the hand away from a hot stove, which cells serve as the effector that produces the response?","options":["Interneurons in the spinal cord","Sensory neurons carrying the signal","Sensory receptors in the skin","Skeletal muscle cells"],"correct":[3],"explanation":"The effector in a reflex arc is the structure that carries out the response. In a withdrawal reflex, skeletal muscle cells contract to move the limb away. Receptors detect the stimulus and neurons relay the signal, but the muscle is the effector."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Cardiovascular System","difficulty":2,"stem":"During ventricular systole, what happens to the heart and its valves?","options":["The ventricles contract and the semilunar valves open to eject blood","The atrioventricular valves open while the ventricles relax","The ventricles relax and fill with blood from the atria","Blood flows backward from the arteries into the ventricles"],"correct":[0],"explanation":"Ventricular systole is the contraction phase. Rising ventricular pressure forces the semilunar (aortic and pulmonary) valves open, ejecting blood into the arteries, while the atrioventricular valves close to prevent backflow into the atria."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Cardiovascular System","difficulty":2,"stem":"Which valve prevents blood from flowing back into the left atrium when the left ventricle contracts?","options":["Tricuspid valve","Aortic valve","Mitral (bicuspid) valve","Pulmonary valve"],"correct":[2],"explanation":"The mitral (bicuspid) valve lies between the left atrium and left ventricle and closes during ventricular contraction to prevent backflow into the left atrium. The tricuspid valve performs the same role on the right side."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Cardiovascular System","difficulty":2,"stem":"Blood leaving the right ventricle on its way to the lungs must pass through which valve?","options":["Mitral valve","Tricuspid valve","Pulmonary valve","Aortic valve"],"correct":[2],"explanation":"The pulmonary (semilunar) valve sits between the right ventricle and the pulmonary trunk. When the right ventricle contracts, blood passes through this valve toward the lungs. The aortic valve serves the left ventricle and the systemic circuit."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Immune System","difficulty":2,"stem":"One major function of the lymphatic system is to","options":["Secrete hormones that regulate blood glucose","Return excess interstitial fluid to the bloodstream","Produce digestive enzymes for the small intestine","Pump oxygenated blood to body tissues"],"correct":[1],"explanation":"The lymphatic system collects excess fluid that leaks from capillaries into the tissues and returns it to the bloodstream as lymph. It does not pump blood, produce digestive enzymes, or regulate blood glucose."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Immune System","difficulty":2,"stem":"Which structures act as filters along lymphatic vessels, trapping pathogens and housing immune cells that mount a defense?","options":["Alveoli","Nephrons","Lymph nodes","Villi"],"correct":[2],"explanation":"Lymph nodes are small bean-shaped organs spaced along lymphatic vessels that filter lymph, trapping bacteria and other pathogens while lymphocytes inside attack them. Alveoli are in the lungs, nephrons in the kidneys, and villi in the small intestine."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Skeletal System","difficulty":1,"stem":"Which of the following bones is part of the axial skeleton rather than the appendicular skeleton?","options":["Clavicle","Femur","Humerus","Sternum"],"correct":[3],"explanation":"The axial skeleton includes the skull, vertebral column, and rib cage (including the sternum). The femur, humerus, and clavicle belong to the appendicular skeleton, which comprises the limbs and the girdles that attach them."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Skeletal System","difficulty":2,"stem":"The shoulder and hip joints allow rotation and movement in many directions. What type of joint are they?","options":["Ball-and-socket joint","Pivot joint","Gliding joint","Hinge joint"],"correct":[0],"explanation":"Ball-and-socket joints, such as the shoulder and hip, have a rounded head that fits into a cup-shaped socket, permitting movement in all planes plus rotation. Hinge joints move in one plane, pivot joints allow rotation around an axis, and gliding joints permit small sliding motions."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Skeletal System","difficulty":2,"stem":"The elbow allows the forearm to bend and straighten in a single plane, much like a door. This is an example of which type of joint?","options":["Ball-and-socket joint","Pivot joint","Hinge joint","Saddle joint"],"correct":[2],"explanation":"A hinge joint, like the elbow or knee, permits movement in only one plane (flexion and extension), similar to a door hinge. Ball-and-socket joints move in many directions, while pivot joints allow rotation."},
  {"section":"SCIENCE","topic":"anatomy-physiology","subtopic":"Skeletal System","difficulty":3,"stem":"The joint between the first and second cervical vertebrae lets the head rotate from side to side, as in shaking the head to signal no. Which type of joint makes this rotation possible?","options":["Ball-and-socket joint","Gliding joint","Pivot joint","Hinge joint"],"correct":[2],"explanation":"A pivot joint allows one bone to rotate around another along a single axis. The joint between the first cervical vertebra (atlas) and second (axis) is a pivot joint that lets the head turn side to side. Hinge joints only bend, and gliding joints only slide."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":1,"stem":"What is the primary purpose of mitosis in multicellular organisms?","options":["To produce gametes for sexual reproduction","To allow growth and to repair damaged tissues","To generate genetic variation among offspring","To reduce the chromosome number by half"],"correct":[1],"explanation":"Mitosis produces two genetically identical diploid cells, which allows an organism to grow and to replace or repair damaged or worn-out cells. Producing gametes, halving the chromosome number, and generating genetic variation are functions of meiosis."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":1,"type":"ORDERED","stem":"Place the four phases of mitosis in the correct order from first to last.","options":["Metaphase","Anaphase","Prophase","Telophase"],"correct":[2,0,1,3],"explanation":"The phases of mitosis occur in a fixed order: prophase (chromosomes condense), metaphase (chromosomes line up at the cell's center), anaphase (sister chromatids separate to opposite poles), and telophase (two new nuclei form). A common way to remember the sequence is the order P, M, A, T."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":2,"stem":"During which phase of mitosis do the chromosomes line up along the middle of the cell?","options":["Prophase","Anaphase","Telophase","Metaphase"],"correct":[3],"explanation":"In metaphase the chromosomes align along the equator, or middle, of the cell. In prophase chromosomes condense, in anaphase sister chromatids are pulled apart, and in telophase two new nuclei form."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":2,"stem":"A diploid parent cell with 46 chromosomes divides by mitosis. How do the resulting daughter cells compare to the parent cell?","options":["Two daughter cells, each with 23 chromosomes and genetically varied","Four daughter cells, each with 46 chromosomes and genetically varied","Two daughter cells, each with 46 chromosomes and genetically identical to the parent","Four daughter cells, each with 23 chromosomes and genetically identical to the parent"],"correct":[2],"explanation":"Mitosis produces two daughter cells that are genetically identical to each other and to the parent cell, each retaining the full diploid number of 46 chromosomes. Producing four cells with half the chromosome number is a feature of meiosis."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":1,"stem":"What is the main purpose of meiosis?","options":["To repair damaged body tissues","To produce two identical diploid cells for growth","To produce four genetically varied haploid gametes","To replace old cells throughout the body"],"correct":[2],"explanation":"Meiosis is the form of cell division that produces gametes, such as sperm and egg cells. It yields four haploid cells that are genetically different from one another and from the parent cell. Tissue repair, growth, and cell replacement are accomplished by mitosis."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":2,"stem":"A human cell with 46 chromosomes undergoes meiosis. How many chromosomes will each resulting gamete contain?","options":["92","12","23","46"],"correct":[2],"explanation":"Meiosis reduces the chromosome number by half, so a diploid human cell with 46 chromosomes produces haploid gametes that each contain 23 chromosomes. When two gametes join during fertilization, the diploid number of 46 is restored."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":3,"stem":"During meiosis, homologous chromosomes pair up and exchange segments of genetic material. What is the name and effect of this process?","options":["Replication, which makes an identical copy of each chromosome","Condensation, which makes the chromosomes shorter and thicker","Crossing over, which increases genetic variation in the gametes","Cytokinesis, which divides the cytoplasm of the cell"],"correct":[2],"explanation":"Crossing over occurs when paired homologous chromosomes exchange corresponding segments of DNA. This recombination produces new combinations of alleles, increasing the genetic variation found among the resulting gametes."},
  {"section":"SCIENCE","topic":"biology","subtopic":"Describe Cell Structure, Function, and Organization","difficulty":3,"stem":"Which statement correctly contrasts mitosis and meiosis?","options":["Mitosis produces two identical diploid cells, while meiosis produces four genetically varied haploid cells","Mitosis produces gametes, while meiosis produces body cells","Mitosis produces four cells, while meiosis produces two cells","Mitosis halves the chromosome number, while meiosis keeps it the same"],"correct":[0],"explanation":"Mitosis results in two diploid daughter cells that are genetically identical to the parent and is used for growth and repair. Meiosis results in four haploid cells that are genetically varied and is used to produce gametes for sexual reproduction."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"An ionic bond forms when sodium reacts with chlorine. Which statement best describes how this bond is created?","options":["Protons move from chlorine to sodium","An electron is transferred from the metal atom to the nonmetal atom","Electrons are shared equally between the two atoms","The atoms exchange neutrons to become stable"],"correct":[1],"explanation":"Ionic bonds form between a metal and a nonmetal by transfer of electrons. Sodium (a metal) loses an electron and chlorine (a nonmetal) gains it, producing oppositely charged ions that attract."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"Two nonmetal atoms join together by sharing electrons. What type of chemical bond is this?","options":["Nuclear bond","Ionic bond","Covalent bond","Metallic bond"],"correct":[2],"explanation":"A covalent bond is formed when two nonmetal atoms share electrons rather than transferring them. This sharing allows each atom to achieve a more stable electron arrangement."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":3,"stem":"In a polar covalent bond, the shared electrons are pulled more strongly toward one atom, creating partial charges. Which molecule contains polar covalent bonds?","options":["H2O, in which oxygen attracts electrons more than hydrogen","N2, made of two identical nitrogen atoms","O2, made of two identical oxygen atoms","Cl2, made of two identical chlorine atoms"],"correct":[0],"explanation":"A bond is polar when electrons are shared unequally because one atom attracts them more strongly. In H2O, oxygen pulls the shared electrons more than hydrogen, creating partial charges. Bonds between two identical atoms (O2, N2, Cl2) are nonpolar."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"How many valence electrons does a neutral oxygen atom have, given that oxygen is in group 16 (6A) of the periodic table?","options":["4","6","8","2"],"correct":[1],"explanation":"Valence electrons are the electrons in the outermost shell. Elements in group 16 (6A) have 6 valence electrons, which is why oxygen tends to gain 2 electrons to complete its outer shell."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"The first electron shell of an atom can hold a maximum of how many electrons?","options":["2","18","8","4"],"correct":[0],"explanation":"The first (innermost) electron shell holds a maximum of 2 electrons. The next shells commonly hold up to 8 electrons each in the lighter elements."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":3,"stem":"According to the octet rule, why are noble gases such as neon and argon chemically unreactive?","options":["Their outer electron shell is already full with eight electrons","They readily transfer electrons to other atoms","They contain only neutrons in the nucleus","They have no electrons in their outer shell"],"correct":[0],"explanation":"The octet rule states that atoms are stable when their outer shell holds eight electrons. Noble gases already have full outer shells, so they have little tendency to gain, lose, or share electrons and are unreactive."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":1,"stem":"Which of the following is classified as an element?","options":["Table salt (NaCl)","Water (H2O)","Pure gold (Au)","Air"],"correct":[2],"explanation":"An element is a pure substance made of only one kind of atom. Pure gold consists only of gold atoms. Water and table salt are compounds, and air is a mixture of gases."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"What is the key difference between a compound and a mixture?","options":["A compound always contains one element, while a mixture contains many","A compound can be separated by filtering, while a mixture cannot be separated","A compound is always a gas, while a mixture is always a liquid","A compound has its components chemically bonded, while a mixture has them only physically combined"],"correct":[3],"explanation":"In a compound, elements are chemically bonded in fixed ratios and form a new substance. In a mixture, substances are only physically combined and keep their own properties, so they can be separated by physical means."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"Which of the following is a pure substance rather than a mixture?","options":["Salt water","Italian salad dressing","Sand mixed with iron filings","Carbon dioxide (CO2)"],"correct":[3],"explanation":"A pure substance has a fixed, uniform composition. Carbon dioxide is a compound with a constant composition, making it a pure substance. The others are mixtures whose components can be physically separated."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"A hydrocarbon is a type of organic molecule. Which elements make up a hydrocarbon?","options":["Carbon, hydrogen, and nitrogen","Hydrogen and oxygen only","Carbon and hydrogen only","Carbon and oxygen only"],"correct":[2],"explanation":"Hydrocarbons are organic compounds composed only of carbon and hydrogen atoms. Methane (CH4) and propane (C3H8) are examples."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"Which functional group is characteristic of an alcohol such as ethanol?","options":["A carboxyl group (COOH)","An amino group (NH2)","A hydroxyl group (OH)","A carbonyl group (C=O)"],"correct":[2],"explanation":"Alcohols are organic molecules that contain a hydroxyl group, written as OH, attached to a carbon atom. Ethanol (C2H5OH) is a common example."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Recognize Basic Atomic Structure","difficulty":2,"stem":"Carbon is central to organic chemistry partly because of how many covalent bonds a carbon atom typically forms. How many bonds is this?","options":["3","4","2","1"],"correct":[1],"explanation":"A carbon atom has 4 valence electrons and typically forms 4 covalent bonds. This ability to form four bonds lets carbon build long chains, branches, and rings, the basis of organic molecules."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Explain Physical Properties and Changes of Matter","difficulty":2,"stem":"Specific heat is the amount of heat needed to raise the temperature of 1 gram of a substance by 1 degree Celsius. A substance with a high specific heat will do which of the following?","options":["Require a large amount of heat to change its temperature","Heat up and cool down very quickly","Be unable to absorb any heat energy","Always remain at the same temperature"],"correct":[0],"explanation":"A high specific heat means a substance needs a large amount of heat energy to change its temperature. Such substances heat up and cool down slowly."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Explain Physical Properties and Changes of Matter","difficulty":2,"stem":"Water has an unusually high specific heat compared to most common substances. Which is a direct consequence of this property?","options":["Water freezes faster than most liquids","Large bodies of water help moderate nearby temperatures by resisting rapid temperature change","Water cannot be used to cool engines","Water boils at a very low temperature"],"correct":[1],"explanation":"Because water has a high specific heat, it absorbs or releases large amounts of heat with only small temperature changes. This allows oceans and lakes to moderate the temperature of surrounding areas."},
  {"section":"SCIENCE","topic":"chemistry","subtopic":"Explain Physical Properties and Changes of Matter","difficulty":2,"stem":"Thermal conduction is the transfer of heat through a material. Which of the following is the best thermal conductor?","options":["A rubber glove","A copper metal rod","A foam cup","A wooden spoon"],"correct":[1],"explanation":"Metals such as copper are good thermal conductors because their freely moving electrons transfer heat quickly. Wood, foam, and rubber are insulators that resist heat flow."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Hyphens","difficulty":1,"stem":"Which sentence uses hyphens correctly?","options":["She is a well-known-author in the science fiction community.","She is a wellknown author in the science fiction community.","She is a well known author in the science fiction community.","She is a well-known author in the science fiction community."],"correct":[3],"explanation":"A compound modifier placed before the noun it describes is hyphenated, so 'well-known author' is correct. Leaving it open ('well known') or closed ('wellknown') is wrong, and the noun 'author' is not joined to the modifier with a hyphen."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Hyphens","difficulty":2,"stem":"Which sentence uses hyphens correctly?","options":["Their five year-old child started kindergarten this fall.","Their five-year old child started kindergarten this fall.","Their five year old child started kindergarten this fall.","Their five-year-old child started kindergarten this fall."],"correct":[3],"explanation":"When 'five year old' works as a compound modifier before the noun 'child,' all three words are joined: 'five-year-old child.' Omitting a hyphen or hyphenating only part of the phrase is incorrect."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Hyphens","difficulty":2,"stem":"Which sentence uses hyphens correctly?","options":["The committee counted thirty-seven-votes in favor of the motion.","The committee counted thirtyseven votes in favor of the motion.","The committee counted thirty seven votes in favor of the motion.","The committee counted thirty-seven votes in favor of the motion."],"correct":[3],"explanation":"Compound numbers from twenty-one through ninety-nine are hyphenated when written out, so 'thirty-seven' is correct. Writing it open or closed is wrong, and the number should not be hyphenated to the noun 'votes.'"},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Hyphens","difficulty":3,"stem":"Which sentence uses hyphens correctly?","options":["The amendment needed a two-thirds-majority to pass.","The amendment needed a twothirds majority to pass.","The amendment needed a two thirds majority to pass.","The amendment needed a two-thirds majority to pass."],"correct":[3],"explanation":"A fraction used as a modifier before a noun is hyphenated, so 'two-thirds majority' is correct. The fraction should not be left open or closed, and 'majority' is the noun, not part of the hyphenated modifier."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Hyphens","difficulty":3,"stem":"Which option is hyphenated correctly?","options":["The senator's ex husband led the anti American protest with self confidence.","The senator's ex-husband led the antiamerican protest with self-confidence.","The senator's ex-husband led the anti-American protest with self-confidence.","The senator's exhusband led the antiAmerican protest with selfconfidence."],"correct":[2],"explanation":"The prefixes ex-, anti-, and self- take a hyphen: 'ex-husband,' 'self-confidence,' and 'anti-American' (anti- is hyphenated before a capitalized proper adjective, which also keeps its capital A). Closing or opening these forms, or lowercasing 'American,' is incorrect."},
  {"section":"ENGLISH","topic":"conventions","subtopic":"Using Hyphens","difficulty":2,"stem":"Which sentence uses hyphens correctly?","options":["A quickly-moving car sped past the newly-painted fence.","A quickly moving car sped past the newly-painted fence.","A quickly-moving car sped past the newly painted fence.","A quickly moving car sped past the newly painted fence."],"correct":[3],"explanation":"Adverbs ending in -ly are not hyphenated to the adjective that follows them, so 'quickly moving' and 'newly painted' both stay open. Adding a hyphen after an -ly adverb is incorrect."},
];
